uart_tx u_tx(
    /*input               */.clk         (clk           ),
    /*input               */.rst_n       (rst_n         ),
    /*input       [1:0]   */.baud_sel    (baud_sel      ),//选择波特率
    /*input               */.tx_byte_vld (tx_data_vld   ),//相当于一个发送请求
    /*input       [7:0]   */.tx_byte     (tx_data       ),
    /*output              */.busy        (tx_busy       ),//忙状态指示  握手信号
    /*output              */.tx_dout     (uart_txd      )
